import { useEffect, useState } from "react";
import { Search, BarChart3, Volume2, Eye, Activity } from "lucide-react";
import CompanyItem from "../components/CompanyItem";
import MetricCard from "../components/MetricCard";
import AIPrediction from "../components/AIPrediction";
import ChartArea from "../components/ChartArea";
import { fetchCompanies } from "../utils/api";

const StockDashboard = () => {
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  // Fetch company list
  useEffect(() => {
    fetchCompanies().then((res) => setCompanies(res.data));
  }, []);

  // Filter search results
  const filteredCompanies = companies.filter(
    (c) =>
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.symbol.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // Handle company selection
  const handleCompanySelect = (company) => {
    setSelectedCompany(company);
    setIsLoading(true);
    setTimeout(() => setIsLoading(false), 1500); // mock loading
  };

  // Chart data (safe check)
  const chartData =
    selectedCompany &&
    selectedCompany.historical_data &&
    Array.isArray(selectedCompany.historical_data.labels) &&
    Array.isArray(selectedCompany.historical_data.data)
      ? {
          labels: selectedCompany.historical_data.labels,
          datasets: [
            {
              data: selectedCompany.historical_data.data,
              borderColor: "#3b82f6",
              backgroundColor: "rgba(59, 130, 246, 0.08)",
              borderWidth: 3,
              fill: true,
            },
          ],
        }
      : null;

  return (
    <div className="flex h-screen bg-gradient-to-br from-slate-50 to-blue-50">
      {/* Sidebar */}
      <div className="w-96 bg-white shadow-2xl border-r border-gray-200 flex flex-col">
        {/* Search */}
        <div className="p-4 bg-gradient-to-r from-gray-50 to-blue-50 border-b border-gray-100">
          <div className="relative group">
            <Search
              className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400"
              size={18}
            />
            <input
              type="text"
              placeholder="Search stocks..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 bg-white border border-gray-200 rounded-2xl"
            />
          </div>
        </div>

        {/* Company List */}
        <div className="flex-1 overflow-y-auto py-2">
          {filteredCompanies.map((c) => (
            <CompanyItem
              key={c.id}
              company={c}
              isActive={selectedCompany?.id === c.id}
              onClick={() => handleCompanySelect(c)}
            />
          ))}
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col">
        {/* Metrics */}
        {selectedCompany && (
          <div className="p-6 bg-white shadow-sm border-b border-gray-200">
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
              <MetricCard
                label="Current Price"
                value={`₹${selectedCompany.current_price}`}
                icon={Eye}
              />
              <MetricCard
                label="Market Cap"
                value={selectedCompany.market_cap}
                icon={BarChart3}
              />
              <MetricCard
                label="Volume"
                value={selectedCompany.volume}
                icon={Volume2}
              />
              <MetricCard
                label="P/E Ratio"
                value={selectedCompany.pe}
                icon={Activity}
              />
            </div>
          </div>
        )}

        {/* Chart + AI Prediction */}
        <div className="flex-1 p-6 grid grid-cols-3 gap-6">
          {/* Chart Area */}
          <div className="col-span-2">
            <ChartArea
              selectedCompany={selectedCompany}
              isLoading={isLoading}
              chartData={chartData}
            />
          </div>

          {/* AI Predictions */}
          {selectedCompany && (
            <div className="col-span-1 bg-white rounded-3xl shadow-xl border border-gray-200 p-4">
              <AIPrediction company={selectedCompany} isLoading={isLoading} />
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default StockDashboard;
